import ast, os

# 检查 src/main.py re-export 是否包含所有模块的公开名字
with open('src/main.py') as f:
    tree = ast.parse(f.read())

re_exported = set()
for node in ast.walk(tree):
    if isinstance(node, ast.ImportFrom):
        for alias in node.names:
            name = alias.asname or alias.name
            re_exported.add(name)

# 检查每个源文件的公开名字
src_files = [f for f in os.listdir('src') if f.endswith('.py') and f not in ('__init__.py', 'main.py')]
missing = {}
for fname in sorted(src_files):
    with open(f'src/{fname}') as f:
        mod_tree = ast.parse(f.read())

    public_names = set()
    for node in ast.iter_child_nodes(mod_tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if not node.name.startswith('_'):
                public_names.add(node.name)
        elif isinstance(node, ast.ClassDef):
            if not node.name.startswith('_'):
                public_names.add(node.name)
        elif isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and not target.id.startswith('_') and target.id.isupper():
                    public_names.add(target.id)

    not_exported = public_names - re_exported
    if not_exported:
        missing[fname] = sorted(not_exported)

if missing:
    print('❌ re-export 缺失:')
    for f, names in missing.items():
        print(f'  {f}: {names}')
else:
    print('✅ src/main.py re-export 完整')
"
